sql:
SELECT DISTINCT network
FROM user_access
ORDER BY network;

external_knowledge:
Average transaction fee = (safeLow fee + average fee + fast fee + fastest fee) / 4; 
Top 5 users with the most network accesses are determined by the count of network accesses in descending order; 
The year 2023 is considered for transaction fee analysis.

sql:
SELECT network, AVG(average) AS avg_transaction_fee
FROM transaction_fees
GROUP BY network;

SELECT DISTINCT tf.network
FROM transaction_fees AS tf
JOIN user_access AS ua ON tf.network = ua.network;

SELECT DISTINCT network
FROM transaction_fees
ORDER BY network;

SELECT network
FROM transaction_fees
WHERE transaction_count = (SELECT MAX(transaction_count) FROM transaction_fees);

SELECT network, average
FROM transaction_fees
WHERE block_num = (SELECT MAX(block_num) FROM transaction_fees);

external_knowledge:
Blockchain network refers to a decentralized system that enables secure and transparent transactions; 
User access count refers to the number of times a user has accessed a particular blockchain network; 
Average transaction fee refers to the estimated cost of processing a transaction on a blockchain network.

sql:
SELECT network, average
FROM transaction_fees
ORDER BY average DESC;

SELECT AVG(average) AS avg_transaction_fee
FROM transaction_fees
WHERE block_num = 12345 AND network = 'ethereum';

SELECT DISTINCT network
FROM transaction_fees
ORDER BY network;
